<body>
<div class="topline"></div>
<nav>
  <div class="brand"><span class="brand-mark">W</span> WASTEDTOKEN MINT</div>
  <div><a href="#about">The Mint</a><a href="#collection">Editions</a><a href="#collection">Acquire</a></div>
</nav>

<header>
  <div class="hero-copy">
    <div class="eyebrow">Proof of legend · struck in metal</div>
    <h1>Hold the token.</h1>
    <p>Limited physical challenge coins for people who know that a digital flex deserves a heavier receipt.</p>
  </div>
  <div class="coin-stage">
    <canvas id="coin-hero" width="900" height="540" aria-label="Animated rotating WastedToken Mint coin"></canvas>
  </div>
  <div class="turn-note">Rotate the proof · front / edge / reverse</div>
</header>

<main>
  <section id="about" class="about">
    <div>
      <div class="section-label">The mint</div>
      <h2>Made for the terminally online. Built to outlast us all.</h2>
    </div>
    <div>
      <p>WastedToken Mint turns improbable internet conviction into heirloom-grade challenge coins. Every issue is sculpted in relief, struck with a proper reeded edge, and finished by hand in a tiny run.</p>
      <p>No wallet connection. No forgotten seed phrase. Just an honest piece of metal with a story you can put in somebody's palm.</p>
      <div class="facts">
        <div class="fact"><b>39 mm</b><span>Collector diameter</span></div>
        <div class="fact"><b>4.2 mm</b><span>Deep struck relief</span></div>
        <div class="fact"><b>100%</b><span>Physical proof</span></div>
      </div>
    </div>
  </section>

  <section id="collection">
    <div class="collection-head">
      <div><div class="section-label">Genesis collection</div><h2>Pick your proof.</h2></div>
      <p>One emblem. Four finishes. Each coin carries its edition number around the rim and its token count on the reverse.</p>
    </div>
    <div class="collection">
      <div class="edition available" data-edition="bronze" data-state="available">
        <canvas class="edition-canvas" width="360" height="240"></canvas>
        <div class="edition-meta"><h3>Bronze</h3><p>The first strike. Warm, weathered, impossible to fake.</p><span class="tag">Available · 240 struck</span><button class="buy">Add to cart</button></div>
      </div>
      <div class="edition available" data-edition="silver" data-state="available">
        <canvas class="edition-canvas" width="360" height="240"></canvas>
        <div class="edition-meta"><h3>Silver</h3><p>Cold brilliance for the keeper of the clean ledger.</p><span class="tag">Available · 120 struck</span><button class="buy">Add to cart</button></div>
      </div>
      <div class="edition sold-out" data-edition="gold" data-state="sold-out">
        <canvas class="edition-canvas" width="360" height="240"></canvas>
        <div class="edition-meta"><h3>Gold</h3><p>The gilded genesis run disappeared before the block cooled.</p><span class="tag">SOLD OUT</span></div>
      </div>
      <div class="edition coming-soon" data-edition="black" data-state="coming-soon">
        <canvas class="edition-canvas" width="360" height="240"></canvas>
        <div class="edition-meta"><h3>Black Obsidian</h3><p>Black nickel with a mirror-dark proof field.</p><span class="tag">Minting Winter 2025</span></div>
      </div>
    </div>
  </section>
</main>
<footer><span>© WastedToken Mint</span><span>Keep the proof close.</span></footer>

<script>
(function(){
  const hero = document.getElementById('coin-hero');
  const palettes = {
    bronze:{base:'#9b5732',light:'#e7ae70',dark:'#321710',rim:'#d38a50'},
    silver:{base:'#8aa8b2',light:'#f7ffff',dark:'#253640',rim:'#ccecf2'},
    gold:{base:'#b88625',light:'#fff0a1',dark:'#4c2d05',rim:'#edc75f'},
    black:{base:'#25313a',light:'#9dacb2',dark:'#03070b',rim:'#56666e'},
    hero:{base:'#698f9b',light:'#eeffff',dark:'#14242c',rim:'#a9dce4'}
  };

  function ellipsePath(ctx,cx,cy,rx,ry){
    ctx.beginPath(); ctx.ellipse(cx,cy,Math.max(1,rx),Math.max(1,ry),0,0,Math.PI*2);
  }
  function reliefText(ctx, text, x, y, size, align, fill, dark, light){
    ctx.save();
    ctx.textAlign=align; ctx.textBaseline='middle';
    ctx.font='900 '+size+'px Arial';
    ctx.fillStyle=dark; ctx.fillText(text,x+2.1,y+2.1);
    ctx.fillStyle=light; ctx.fillText(text,x-1.25,y-1.25);
    ctx.fillStyle=fill; ctx.fillText(text,x,y);
    ctx.restore();
  }
  function ringText(ctx, text, y, size, color){
    ctx.save();
    ctx.font='700 '+size+'px Arial'; ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillStyle=color; ctx.fillText(text,0,y);ctx.restore();
  }
  function drawRidges(ctx,cx,cy,ry,width,pal){
    const h=ry*2+13;
    const g=ctx.createLinearGradient(cx-width/2,0,cx+width/2,0);
    g.addColorStop(0,pal.dark);g.addColorStop(.22,pal.rim);g.addColorStop(.48,pal.light);g.addColorStop(.74,pal.dark);g.addColorStop(1,pal.rim);
    ctx.fillStyle=g;
    ctx.beginPath();ctx.roundRect(cx-width/2,cy-h/2,width,h,Math.min(width/2,12));ctx.fill();
    ctx.save();
    ctx.beginPath();ctx.roundRect(cx-width/2,cy-h/2,width,h,Math.min(width/2,12));ctx.clip();
    for(let x=cx-width/2+3;x<cx+width/2;x+=4.5){
      ctx.strokeStyle=(Math.round((x-cx)*2)%3===0)?'rgba(255,255,255,.46)':'rgba(0,0,0,.5)';
      ctx.lineWidth=1.4;ctx.beginPath();ctx.moveTo(x,cy-h/2);ctx.lineTo(x,cy+h/2);ctx.stroke();
    }
    ctx.restore();
    ctx.strokeStyle='rgba(0,0,0,.7)';ctx.lineWidth=2;ctx.stroke();
  }
  function drawFace(ctx,cx,cy,rx,ry,R,pal,isBack,t,detail){
    const yaw=2*Math.PI*t, pitch=4*Math.PI*t+.55;
    ellipsePath(ctx,cx,cy,rx,ry);ctx.save();ctx.clip();

    const metal=ctx.createLinearGradient(cx-rx,cy-ry,cx+rx,cy+ry);
    metal.addColorStop(0,pal.dark);
    metal.addColorStop(.19,pal.base);
    metal.addColorStop(.43,pal.light);
    metal.addColorStop(.54,pal.base);
    metal.addColorStop(.78,pal.dark);
    metal.addColorStop(1,pal.rim);
    ctx.fillStyle=metal;ctx.fillRect(cx-rx-3,cy-ry-3,rx*2+6,ry*2+6);

    const sx=cx + rx*(.60*Math.sin(yaw*1.13+.4));
    const sy=cy + ry*(.45*Math.cos(pitch-.4));
    const shine=ctx.createRadialGradient(sx,sy,2,sx,sy,Math.max(rx,ry)*.66);
    shine.addColorStop(0,'rgba(255,255,255,.93)');
    shine.addColorStop(.12,'rgba(255,255,255,.52)');
    shine.addColorStop(.34,'rgba(217,250,255,.16)');
    shine.addColorStop(.63,'rgba(255,255,255,0)');
    ctx.fillStyle=shine;ctx.fillRect(cx-rx-4,cy-ry-4,rx*2+8,ry*2+8);

    const slash=ctx.createLinearGradient(cx-rx,cy,cx+rx,cy);
    slash.addColorStop(0,'rgba(0,0,0,.13)');slash.addColorStop(.44,'rgba(255,255,255,.03)');
    slash.addColorStop(.53,'rgba(255,255,255,.32)');slash.addColorStop(.61,'rgba(255,255,255,.03)');slash.addColorStop(1,'rgba(0,0,0,.18)');
    ctx.fillStyle=slash;ctx.fillRect(cx-rx,cy-ry,rx*2,ry*2);
    ctx.restore();

    ctx.save();
    ctx.translate(cx,cy);ctx.scale(rx/R,ry/R);
    ctx.lineWidth=8;ctx.strokeStyle='rgba(12,22,27,.74)';ellipsePath(ctx,0,0,R*.89,R*.89);ctx.stroke();
    ctx.lineWidth=2.4;ctx.strokeStyle=pal.light;ctx.globalAlpha=.6;ellipsePath(ctx,0,0,R*.82,R*.82);ctx.stroke();ctx.globalAlpha=1;

    if(detail){
      if(!isBack){
        ringText(ctx,'WASTEDTOKEN  •  MINT  •  WASTEDTOKEN',-R*.61,10,pal.light);
        ringText(ctx,'PHYSICAL PROOF OF LEGEND',R*.61,9,pal.light);
        ctx.strokeStyle='rgba(18,28,31,.65)';ctx.lineWidth=5;
        ctx.beginPath();ctx.arc(0,0,R*.46,0,Math.PI*2);ctx.stroke();
        ctx.strokeStyle=pal.light;ctx.globalAlpha=.6;ctx.lineWidth=1.7;
        ctx.beginPath();ctx.arc(-1,-1,R*.46,0,Math.PI*2);ctx.stroke();ctx.globalAlpha=1;
        reliefText(ctx,'W',0,8,R*.72,'center',pal.base,pal.dark,pal.light);
        ctx.strokeStyle=pal.light;ctx.lineWidth=4;ctx.beginPath();
        ctx.moveTo(-R*.38,R*.28);ctx.quadraticCurveTo(0,R*.43,R*.38,R*.28);ctx.stroke();
        ctx.fillStyle=pal.light;
        for(let i=0;i<8;i++){let a=i*Math.PI/4;ctx.beginPath();ctx.arc(Math.cos(a)*R*.64,Math.sin(a)*R*.64,3.2,0,Math.PI*2);ctx.fill()}
      } else {
        ringText(ctx,'WASTEDTOKEN RESERVE',-R*.61,10,pal.light);
        ringText(ctx,'NO KEYS • NO GAS • JUST METAL',R*.61,8,pal.light);
        ctx.strokeStyle='rgba(13,23,27,.68)';ctx.lineWidth=5;ellipsePath(ctx,0,0,R*.51,R*.51);ctx.stroke();
        ctx.strokeStyle=pal.light;ctx.globalAlpha=.55;ctx.lineWidth=1.5;ellipsePath(ctx,-1,-1,R*.51,R*.51);ctx.stroke();ctx.globalAlpha=1;
        reliefText(ctx,'10,000',0,-R*.08,R*.31,'center',pal.base,pal.dark,pal.light);
        reliefText(ctx,'TOKENS',0,R*.24,R*.14,'center',pal.base,pal.dark,pal.light);
        ctx.strokeStyle=pal.light;ctx.lineWidth=2;
        ctx.beginPath();ctx.moveTo(-R*.34,R*.39);ctx.lineTo(R*.34,R*.39);ctx.stroke();
        ringText(ctx,'REDEEMED IN GLORY',R*.48,8,pal.light);
      }
    }
    ctx.restore();
    ellipsePath(ctx,cx,cy,rx,ry);ctx.lineWidth=Math.max(2,Math.min(rx,ry)*.035);ctx.strokeStyle='rgba(5,10,13,.85)';ctx.stroke();
    ellipsePath(ctx,cx-1,cy-1,Math.max(1,rx-4),Math.max(1,ry-4));ctx.lineWidth=1.5;ctx.strokeStyle='rgba(255,255,255,.36)';ctx.stroke();
  }
  function renderCoin(canvas,t,kind,edition){
    const ctx=canvas.getContext('2d'), w=canvas.width,h=canvas.height;
    const pal=palettes[kind]||palettes.hero;
    ctx.clearRect(0,0,w,h);
    ctx.fillStyle=edition ? '#101c27' : '#09131c';
    ctx.fillRect(0,0,w,h);
    const R=edition?Math.min(w*.34,h*.37):Math.min(w*.235,h*.35);
    const cx=w/2,cy=h/2;
    const yaw=2*Math.PI*t, pitch=4*Math.PI*t+.55;
    const cyaw=Math.cos(yaw), cpitch=Math.cos(pitch);
    const normal=cyaw*cpitch;
    const rx=R*(.18+.82*Math.abs(cyaw));
    const ry=R*(.22+.78*Math.abs(cpitch));
    const edge=Math.max(0,1-Math.abs(cyaw));
    if(!edition){
      const shadow=ctx.createRadialGradient(cx,cy+R*.92,4,cx,cy+R*.92,R*1.18);
      shadow.addColorStop(0,'rgba(0,0,0,.58)');shadow.addColorStop(1,'rgba(0,0,0,0)');
      ctx.fillStyle=shadow;ctx.beginPath();ctx.ellipse(cx,cy+R*.9,R*1.04,R*.18,0,0,Math.PI*2);ctx.fill();
    }
    if(edge>.11) drawRidges(ctx,cx,cy,ry,18+edge*25,pal);
    const depth=5+edge*7;
    ellipsePath(ctx,cx,cy+depth,rx+2,ry+2);ctx.fillStyle=pal.dark;ctx.fill();
    const detail=Math.abs(normal)>.16;
    drawFace(ctx,cx,cy,rx,ry,R,pal,normal<0,t,detail);
    if(edge>.18){
      ctx.save();ctx.globalAlpha=Math.min(.9,edge);
      ctx.strokeStyle=pal.light;ctx.lineWidth=1;
      for(let i=-4;i<=4;i++){
        const x=cx+i*3.6;
        ctx.beginPath();ctx.moveTo(x,cy-ry*.9);ctx.lineTo(x,cy+ry*.9);ctx.stroke();
      }
      ctx.restore();
    }
  }

  let raf=0, running=true, start=performance.now();
  function frame(now){
    if(!running)return;
    renderCoin(hero,((now-start)%12000)/12000,'hero',false);
    raf=requestAnimationFrame(frame);
  }
  window.demo={
    canvas:hero,
    setTime:function(t){ renderCoin(hero,Math.max(0,Math.min(1,Number(t)||0)),'hero',false); },
    pause:function(){running=false;cancelAnimationFrame(raf);}
  };
  renderCoin(hero,0,'hero',false);
  raf=requestAnimationFrame(frame);

  const editionTimes={bronze:.03,silver:.13,gold:.56,black:.68};
  document.querySelectorAll('.edition').forEach(function(tile){
    const name=tile.dataset.edition;
    renderCoin(tile.querySelector('canvas'),editionTimes[name],name,true);
  });
  document.querySelectorAll('.buy').forEach(function(button){
    button.addEventListener('click',function(){
      button.textContent='Added to your hoard';
      button.style.background='#d8f8ff';
      setTimeout(()=>button.textContent='Add to cart',1500);
    });
  });
})();
</script>
</body>
</html>
